) and STATUS in ('DEPOSIT_FAILED', 'DEPOSIT_SUCCESS', 'DEPOSIT_ABANDONED') and (TRANSACTION_LOCATION_NAME in ('MICHIGAN', 'PENNSYLVANIA', 'NEW_JERSEY', 'NEW_YORK', 'ILLINOIS', 'OHIO', 'CONNECTICUT', 'WEST_VIRGINIA', 'ARIZONA', 'MARYLAND', 'MASSACHUSETTS', 'NORTH_CAROLINA', 'LOUISIANA', 'VIRGINIA', 'INDIANA', 'TENNESSEE', 'MISSOURI', 'COLORADO', 'KENTUCKY', 'IOWA', 'KANSAS', 'WASHINGTON_DC', 'VERMONT', 'CALIFORNIA', 'WYOMING', 'FLORIDA', 'TEXAS', 'GEORGIA', 'WASHINGTON', 'MINNESOTA', 'SOUTH_CAROLINA', 'ALABAMA', 'WISCONSIN', 'OKLAHOMA', 'UTAH', 'MISSISSIPPI', 'OREGON', 'IDAHO', 'HAWAII', 'RHODE_ISLAND', 'DELAWARE', 'NEBRASKA', 'NEW_MEXICO', 'MAINE', 'NEW_HAMPSHIRE', 'NORTH_DAKOTA', 'SOUTH_DAKOTA', 'ALASKA', 'ARKANSAS', 'PUERTO_RICO', 'NEVADA', 'VIRGIN_ISLANDS', 'GUAM') or TRANSACTION_LOCATION_NAME is null) and TRANS_DATE_ALK >= to_timestamp_ntz('2026-01-01 00:00:00.000000000', 'YYYY-MM-DD HH24:MI:SS.FF9') and TRANS_DATE_ALK <= to_timestamp_ntz('2026-03-27 23:59:59.999000000', 'YYYY-MM-DD HH24:MI:SS.FF9') group by DATETRUNC_57) Q1 order by DATETRUNC_57 asc limit 25001

